import * as React from "react"

import { cn } from "@/lib/utils"
import "./spotlight-card.css"

function SpotlightCard({
  className,
  title,
  description,
  image,
  ...props
}: React.ComponentProps<"div"> & {
  title?: string
  description?: string
  image?: React.ReactNode
}) {
  return (
    <div
      data-slot="spotlight-card"
      className={cn("spotlight-card-base", className)}
      {...props}
    >
      <div className="spotlight-card-image">
        {image ?? <div className="spotlight-card-image-fallback" />}
      </div>
      <div className="flex flex-col gap-[var(--layout-gap-xs)] p-[var(--layout-padding-lg)]">
        {title && (
          <p className="text-content-note font-accent [color:var(--text-base-strong)]">
            {title}
          </p>
        )}
        {description && (
          <p className="text-content-caption [color:var(--text-base-moderate)]">
            {description}
          </p>
        )}
      </div>
    </div>
  )
}

export { SpotlightCard }

/* ================================================================
 * SPOTLIGHT CARD — Base, Image & Fallback Styles
 * Structure (flex layout) lives in spotlight-card.tsx.
 * Theming (colors, borders, shadows) lives here via tokens.
 * ================================================================ */

.spotlight-card-base {
  display: flex;
  flex-direction: column;
  overflow: hidden;
  background: var(--background-neutral-lighter-default);
  border: var(--layout-border-thin) solid var(--border-default);
  border-radius: var(--layout-radius-2xl);
  --spotlight-card-shadow:
    0px 0px 1px 0px var(--shadow-neutral-strong),
    0px 2px 2px 0px var(--shadow-neutral-strong),
    0px 4px 3px 0px var(--shadow-neutral-strong);
  box-shadow: var(--spotlight-card-shadow);
}

.dark .spotlight-card-base {
  --spotlight-card-shadow:
    0px 0px 1px 0px var(--shadow-neutral-moderate),
    0px 2px 4px 0px var(--shadow-neutral-moderate),
    0px 4px 6px 0px var(--shadow-neutral-moderate);
}

.spotlight-card-image {
  flex: 1 1 0%;
  min-height: 0;
  overflow: hidden;
}

.spotlight-card-image > img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.spotlight-card-image-fallback {
  width: 100%;
  height: 100%;
  background: linear-gradient(
    135deg,
    var(--background-neutral-medium-hover) 0%,
    var(--background-neutral-lighter-default) 100%
  );
}
